where from_address = #{fromAddress}
  and pay_token = #{payToken}
  and pay_network = #{payNetwork}
  and status in ('pending', 'paid')
  and (tx_hash is null or tx_hash = '' or tx_hash = #{txHash})
order by create_time desc
limit 1



    AND user_id = #{userId}
    AND status = #{status}
    AND order_no = #{orderNo}

order by create_time desc

mapper.update:
update virtual_recharge_order
status = #{status}, tx_hash = #{txHash}, payment_tx_id = #{paymentTxId}, from_address = #{fromAddress}, paid_at = #{paidAt}, completed_at = #{completedAt}, update_time = sysdate()
where order_id = #{orderId}

update virtual_recharge_order
set status = #{status}, update_time = sysdate()
where order_id = #{orderId}

mapper.select:
SELECT o.order_id, o.order_no, o.user_id, o.package_id,
       o.credits_amount, o.bonus_credits, o.pay_network, o.pay_token,
       o.pay_amount, o.pay_amount_display, o.wallet_address, o.from_address,
       o.status, o.order_type, o.tx_hash, o.paid_at, o.create_time, o.update_time,
       COALESCE(p.package_name, '自定义') AS package_name
FROM virtual_recharge_order o
LEFT JOIN virtual_recharge_package p ON p.package_id = o.package_id

    AND o.user_id = #{userId}
    AND o.status = #{status}
    AND o.order_no = #{orderNo}
    AND o.tx_hash = #{txHash}
    AND o.create_time >= #{beginTime}
    AND o.create_time <= #{endTime}

ORDER BY o.create_time DESC
